// Deep link route model
class DeepLinkRoute {
  final String path;
  final Map<String, String> parameters;
  final String? fragment;

  DeepLinkRoute({
    required this.path,
    this.parameters = const {},
    this.fragment,
  });

  @override
  String toString() =>
      'DeepLinkRoute(path: $path, parameters: $parameters, fragment: $fragment)';
}

// Deep link parser
class DeepLinkParser {
  static const String scheme = 'myapp';

  static DeepLinkRoute? parse(String? uriString) {
    if (uriString == null || uriString.isEmpty) return null;

    try {
      final uri = Uri.parse(uriString);

      if (uri.scheme != scheme) return null;

      // Build path from host and path segments
      final segments = <String>[uri.host, ...uri.pathSegments]
          .where((s) => s.isNotEmpty)
          .toList();
      final path = '/${segments.join('/')}';

      // Parse query parameters
      final parameters = Map<String, String>.from(uri.queryParameters);

      // Extract path parameters (e.g., /profile/123 -> id=123)
      final pathParams = _extractPathParameters(segments);
      parameters.addAll(pathParams);

      return DeepLinkRoute(
        path: path,
        parameters: parameters,
        fragment: uri.fragment.isNotEmpty ? uri.fragment : null,
      );
    } catch (e) {
      debugPrint('Error parsing deep link: $e');
      return null;
    }
  }

  static Map<String, String> _extractPathParameters(List<String> segments) {
    final params = <String, String>{};

    if (segments.length >= 2) {
      switch (segments[0]) {
        case 'profile':
          params['userId'] = segments[1];
          break;
        case 'payment':
          params['action'] = segments[1];
          if (segments.length >= 3) {
            params['transactionId'] = segments[2];
          }
          break;
        case 'product':
          params['productId'] = segments[1];
          break;
        case 'campaign':
          params['campaignId'] = segments[1];
          break;
        case 'notification':
          params['notificationId'] = segments[1];
          break;
      }
    }

    return params;
  }
}

// Deep link handler singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static final DeepLinkHandler _instance = DeepLinkHandler._internal();
  factory DeepLinkHandler() => _instance;
  DeepLinkHandler._internal();

  StreamSubscription? _linkSubscription;
  String? _initialLink;
  bool _isInitialized = false;

  final StreamController<DeepLinkRoute> _deepLinkController =
      StreamController<DeepLinkRoute>.broadcast();

  Stream<DeepLinkRoute> get deepLinkStream => _deepLinkController.stream;

  Future<void> initialize() async {
    if (_isInitialized) return;
    _isInitialized = true;

    // Handle initial link (app opened via deep link)
    await _handleInitialLink();

    // Handle incoming links while app is running
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        _processLink(uri?.toString());
      },
      onError: (err) {
        debugPrint('Deep link stream error: $err');
      },
    );
  }

  Future<void> _handleInitialLink() async {
    try {
      _initialLink = await getInitialLink();
      if (_initialLink != null) {
        debugPrint('Initial deep link: $_initialLink');
        _processLink(_initialLink);
      }
    } catch (e) {
      debugPrint('Error getting initial link: $e');
    }
  }

  void _processLink(String? link) {
    if (link == null) return;

    debugPrint('Processing deep link: $link');

    final route = DeepLinkParser.parse(link);
    if (route != null) {
      debugPrint('Parsed route: $route');
      _deepLinkController.add(route);
      _navigateToRoute(route);
    } else {
      debugPrint('Could not parse deep link: $link');
    }
  }

  void _navigateToRoute(DeepLinkRoute route) {
    final navigator = navigatorKey.currentState;
    if (navigator == null) {
      debugPrint('Navigator not available yet, queuing route');
      return;
    }

    // Determine the route name based on the path
    final segments = route.path.split('/').where((s) => s.isNotEmpty).toList();
    if (segments.isEmpty) return;

    String routeName;
    switch (segments[0]) {
      case 'profile':
        routeName = '/profile';
        break;
      case 'payment':
        if (segments.length >= 2 && segments[1] == 'confirm') {
          routeName = '/payment/confirm';
        } else {
          routeName = '/payment';
        }
        break;
      case 'product':
        routeName = '/product';
        break;
      case 'campaign':
        routeName = '/campaign';
        break;
      case 'notification':
        routeName = '/notification';
        break;
      default:
        routeName = '/';
    }

    debugPrint('Navigating to: $routeName with params: ${route.parameters}');

    navigator.pushNamed(
      routeName,
      arguments: route.parameters,
    );
  }

  // Manual deep link processing (e.g., from push notifications)
  void handlePushNotificationLink(String link) {
    _processLink(link);
  }

  void dispose() {
    _linkSubscription?.cancel();
    _deepLinkController.close();
    _isInitialized = false;
  }
}

// App Router
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    final args = settings.arguments as Map<String, String>? ?? {};

    switch (settings.name) {
      case '/':
        return MaterialPageRoute(
          builder: (_) => const HomeScreen(),
          settings: settings,
        );
      case '/profile':
        return MaterialPageRoute(
          builder: (_) => ProfileScreen(
            userId: args['userId'] ?? 'unknown',
            source: args['utm_source'],
          ),
          settings: settings,
        );
      case '/payment':
        return MaterialPageRoute(
          builder: (_) => PaymentScreen(
            transactionId: args['transactionId'],
          ),
          settings: settings,
        );
      case '/payment/confirm':
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmScreen(
            transactionId: args['transactionId'],
            amount: args['amount'],
            currency: args['currency'],
          ),
          settings: settings,
        );
      case '/product':
        return MaterialPageRoute(
          builder: (_) => ProductScreen(
            productId: args['productId'] ?? 'unknown',
            campaignId: args['utm_campaign'],
          ),
          settings: settings,
        );
      case '/campaign':
        return MaterialPageRoute(
          builder: (_) => CampaignScreen(
            campaignId: args['campaignId'] ?? 'unknown',
            source: args['utm_source'],
            medium: args['utm_medium'],
          ),
          settings: settings,
        );
      case '/notification':
        return MaterialPageRoute(
          builder: (_) => NotificationDetailScreen(
            notificationId: args['notificationId'] ?? 'unknown',
          ),
          settings: settings,
        );
      default:
        return MaterialPageRoute(
          builder: (_) => const NotFoundScreen(),
          settings: settings,
        );
    }
  }
}

// Wrapper widget that initializes deep link handling
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

class _DeepLinkWrapperState extends State<DeepLinkWrapper> {
  final DeepLinkHandler _deepLinkHandler = DeepLinkHandler();
  late StreamSubscription<DeepLinkRoute> _routeSubscription;
  final List<DeepLinkRoute> _receivedLinks = [];

  @override
  void initState() {
    super.initState();
    _deepLinkHandler.initialize();

    _routeSubscription = _deepLinkHandler.deepLinkStream.listen((route) {
      setState(() {
        _receivedLinks.add(route);
      });
    });
  }

  @override
  void dispose() {
    _routeSubscription.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return HomeScreen(receivedLinks: _receivedLinks);
  }
}

